const rows = $input.all().map(i => i.json);

// Configure thresholds here (column_name: { min, max })
// Edit these values to match your sheet columns and desired thresholds
const thresholds = JSON.parse($env.ALERT_THRESHOLDS || JSON.stringify({
  revenue: { min: 100, max: null, label: 'Revenue' },
  orders: { min: 5, max: null, label: 'Orders' },
  error_count: { min: null, max: 10, label: 'Error Count' },
  response_time: { min: null, max: 5000, label: 'Response Time (ms)' }
}));

const alerts = [];

for (const row of rows) {
  for (const [col, config] of Object.entries(thresholds)) {
    const value = parseFloat(row[col]);
    if (isNaN(value)) continue;

    const label = config.label || col;

    if (config.min !== null && config.min !== undefined && value < config.min) {
      alerts.push({
        column: label,
        value,
        threshold: config.min,
        direction: 'below minimum',
        row_id: row.id || row.name || row.email || JSON.stringify(row).slice(0, 50)
      });
    }

    if (config.max !== null && config.max !== undefined && value > config.max) {
      alerts.push({
        column: label,
        value,
        threshold: config.max,
        direction: 'above maximum',
        row_id: row.id || row.name || row.email || JSON.stringify(row).slice(0, 50)
      });
    }
  }
}

if (alerts.length === 0) {
  return [{ json: { has_alerts: false, message: 'All values within thresholds' } }];
}

let alertHtml = '<table border="1" cellpadding="8" cellspacing="0"><tr><th>Column</th><th>Value</th><th>Threshold</th><th>Direction</th><th>Row</th></tr>';
for (const a of alerts) {
  alertHtml += `<tr><td>${a.column}</td><td><strong>${a.value}</strong></td><td>${a.threshold}</td><td>${a.direction}</td><td>${a.row_id}</td></tr>`;
}
alertHtml += '</table>';

return [{
  json: {
    has_alerts: true,
    alert_count: alerts.length,
    alert_html: alertHtml,
    checked_at: new Date().toISOString()
  }
}];
